import { useMap } from '@vis.gl/react-maplibre';
import { isUndefined } from 'lodash-es';

import { useMapSelectionState } from '../store/selectors.js';
import type { BubbleLayerProps } from '../types/bubble-layer.js';
import type { ChoroplethLayerProps } from '../types/choropleth-layer.js';
import { isLegendColoring } from '../types/coloring.js';
import type {
  Connection,
  ConnectionLayerProps,
} from '../types/connection-layer.js';
import type { DotLayerProps } from '../types/dot-layer.js';
import type { Location } from '../types/location.js';
import { hasAssociatedFeatures } from '../utils/associated-features.js';

export const useLegendInteractionHighlighting = <
  L extends Location,
  C extends Connection,
  R extends Record<string, unknown>,
>(
  props:
    | DotLayerProps<L>
    | BubbleLayerProps<L>
    | ChoroplethLayerProps<R>
    | ConnectionLayerProps<C>,
  sourceId: string,
) => {
  const { highlightedSeries } = useMapSelectionState();

  const { current: map } = useMap();

  if (isLegendColoring(props) && !isUndefined(map)) {
    // Before highlight, we need to remove previous state (all highlighted symbols)
    const hoveredByLegend = map.querySourceFeatures(sourceId, {
      filter: ['all'],
    });
    hoveredByLegend?.map((ft) =>
      map.setFeatureState(
        { source: sourceId, id: ft.id },
        { legendHover: true },
      ),
    );

    if (hasAssociatedFeatures(sourceId)) {
      const associatedId = `${sourceId}-direction`;

      const hoveredByLegend = map.querySourceFeatures(associatedId, {
        filter: ['all'],
      });

      hoveredByLegend?.map((ft) =>
        map.setFeatureState(
          { source: associatedId, id: ft.id },
          { legendHover: true },
        ),
      );
    }

    if (highlightedSeries) {
      const highlightedSeriesName = highlightedSeries.name;
      const hoveredByLegend = map.querySourceFeatures(sourceId, {
        filter: ['!in', props.valueAccessor, highlightedSeriesName],
      });
      hoveredByLegend?.map((ft) =>
        map.setFeatureState(
          { source: sourceId, id: ft.id },
          { legendHover: false },
        ),
      );

      if (hasAssociatedFeatures(sourceId)) {
        const associatedId = `${sourceId}-direction`;

        const hoveredByLegend = map.querySourceFeatures(associatedId, {
          filter: ['!in', props.valueAccessor, highlightedSeriesName],
        });

        hoveredByLegend?.map((ft) =>
          map.setFeatureState(
            { source: associatedId, id: ft.id },
            { legendHover: false },
          ),
        );
      }
    } else {
      hoveredByLegend?.map((ft) =>
        map.removeFeatureState({ source: sourceId, id: ft.id }, 'legendHover'),
      );
    }
  }
};
